public  static ETGSalesAgreementFixationController construct()
{
    return new ETGSalesAgreementFixationController();
}

public static void main(Args    _args)
{
    ETGSalesAgreementFixationController     salesAgreementFixationController;
    ETGSalesAgreementFixationContract       salesAgreementFixationContract;
    SalesAgreementHeader                    salesAgreementHeader;

    salesAgreementFixationController    =    ETGSalesAgreementFixationController::construct();
    salesAgreementHeader                =    _args.record() as SalesAgreementHeader;

    salesAgreementFixationController    =   new ETGSalesAgreementFixationController(
                                        classStr (ETGSalesAgreementFixationService),
                                        methodStr(ETGSalesAgreementFixationService , generateReportByGER),
                                        SysOperationExecutionMode::Synchronous);
    salesAgreementFixationContract      =   salesAgreementFixationController.getDataContractObject();

    salesAgreementFixationContract.parmSalesAgreementId(salesAgreementHeader.SalesNumberSequence); // Setting the Value of sales order id

    salesAgreementFixationController.parmArgs(_args);
    salesAgreementFixationController.parmShowDialog(false);
    salesAgreementFixationController.startOperation();
}
